CREATE TABLE IF NOT EXISTS "channel_routing_state" ("channel_id" INTEGER NOT NULL PRIMARY KEY, "success_alpha" DOUBLE PRECISION NOT NULL DEFAULT 2, "success_beta" DOUBLE PRECISION NOT NULL DEFAULT 2, "latency_log_mu" DOUBLE PRECISION NOT NULL DEFAULT 0, "latency_log_sigma2" DOUBLE PRECISION NOT NULL DEFAULT 0.8, "latency_n" INTEGER NOT NULL DEFAULT 0, "prompt_ewma" DOUBLE PRECISION NOT NULL DEFAULT 0, "completion_ewma" DOUBLE PRECISION NOT NULL DEFAULT 0, "cache_read_ewma" DOUBLE PRECISION NOT NULL DEFAULT 0, "cache_creation_ewma" DOUBLE PRECISION NOT NULL DEFAULT 0, "pricing_snapshot" JSONB, "manual_weight" DOUBLE PRECISION NOT NULL DEFAULT 1, "version" INTEGER NOT NULL DEFAULT 1, "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("channel_id") REFERENCES "route_channels"("id") ON DELETE CASCADE);
CREATE INDEX "channel_routing_state_updated_at_idx" ON "channel_routing_state" ("updated_at");
